"use strict";parserFactory.register("fictionmania.tv",()=>new FictionManiaParser);class FictionManiaParser extends Parser{constructor(){super()}getChapterUrls(e){let t=util.hyperlinksToChapterList(e.body,this.isChapterHref);return Promise.resolve(t.reverse())}isChapterHref(e){return-1!=e.pathname.indexOf("/stories/readhtmlstory.html")||-1!=e.pathname.indexOf("/stories/readtextstory.html")}findContent(e){let t=util.getElement(e,"div",e=>""!==e.style.marginLeft);return null===t&&(t=e.querySelector("pre")),t}customRawDomToContentStep(e,t){"pre"===t.tagName.toLowerCase()&&util.convertPreTagToPTags(e.rawDom,t,"\n\n")}extractTitleImpl(e){return util.getElement(e.body,"a",e=>this.isChapterHref(e))}extractAuthor(e){let t=e.querySelector("a[href*='/searchdisplay/authordisplay.html?word=']");return null===t?super.extractAuthor(e):t.innerText}}